import React from 'react';
import { Container } from 'react-bootstrap'; 
import HeroSection from '../components/HeroSection'; 

// Este componente es la página principal, ahora reducida para probar el redondeo del Hero.
const HomeScreen = () => {
    return (
        <>
            {/* 1. HERO SECTION: Debe tener la clase 'rounded-b-2xl' aplicada. */}
            {/* Usaremos la versión simple de HeroSection.js que ya solo tiene fondo de color */}
            <HeroSection />

            {/* 2. ÁREA DE CONTENIDO: CRÍTICO para exponer el redondeo del Hero */}
            {/* El fondo blanco (bg-white) y el margen negativo (-mt-24) crearán el contraste */}
            <div className="bg-white min-h-[50vh]">
                
                {/* Margen negativo CRÍTICO: Levanta el contenido 24 unidades (6rem) */}
                <Container className="pt-0 -mt-24 z-20 relative"> 
                    <div className="p-6 rounded-xl shadow-xl border border-gray-100 text-center">
                        <h1 className="text-4xl font-bold text-gray-800">✅ Prueba de Redondeo del Hero</h1>
                        <p className="text-gray-600">
                            Si ves un **bloque de color oscuro redondeado** en la parte superior, Tailwind ya funciona.
                        </p>
                    </div>
                </Container>
            </div>
        </>
    );
};

export default HomeScreen;
